final:
module RefModule(
    input [3:0] inclk,
    input [1:0] clkselect,
    output reg outclk // Changed from wire to reg
);wire [3:0] unused_sel_inclk;
assign unused_sel_inclk[0] = inclk[0];
assign unused_sel_inclk[1] = inclk[1];
assign unused_sel_inclk[2] = inclk[2];
assign unused_sel_inclk[3] = inclk[3];

always @(*) begin
    case(clkselect)
        2'b00: outclk = unused_sel_inclk[0];
        2'b01: outclk = unused_sel_inclk[1];
        2'b10: outclk = unused_sel_inclk[2];
        2'b11: outclk = unused_sel_inclk[3];
        default: outclk = 1'b0;
    endcase
end

endmodule
